// Politics/Tweet event — Twitter API rate-limited, no ctx.news
// Reasoning from market prices + time-to-expiry only

const THRESHOLD = 0.04;

// Market analysis:
// - Window: April 18 16:00 UTC to April 20 16:00 UTC (48 hours total)
// - nowTs: ctx.timing.nowTs ≈ 2026-04-20T07:41 UTC → ~39.7h elapsed, ~8.3h remaining (84% complete)
// - Market strongly prices 40-64 at 0.92 YES
// - 65-89 bucket at 0.0765 YES (~7.65% chance Elon posted more)
// - Implied distribution is very concentrated in 40-64 band
//
// Without Twitter data, my estimates anchor to market consensus with small adjustments:
// The 8.3h remaining (out of 48h) = ~17% of window left
// If count is mid-range of 40-64 (say 52) at 84% complete, rate = 52/39.7h ≈ 1.31 tweets/hr
// Projected additional: 1.31 * 8.3 ≈ 10.9 tweets → final projected: ~63 tweets (still in 40-64)
// But variance exists — slight upside risk to 65-89 range

const estimates = {
  "Will Elon Musk post <40 tweets from April 18 to April 20, 2026?":           0.001,
  "Will Elon Musk post 40-64 tweets from April 18 to April 20, 2026?":         0.905,
  "Will Elon Musk post 65-89 tweets from April 18 to April 20, 2026?":         0.085,
  "Will Elon Musk post 90-114 tweets from April 18 to April 20, 2026?":        0.007,
  "Will Elon Musk post 115-139 tweets from April 18 to April 20, 2026?":       0.0015,
  "Will Elon Musk post 140-164 tweets from April 18 to April 20, 2026?":       0.0005,
  "Will Elon Musk post 165-189 tweets from April 18 to April 20, 2026?":       0.0002,
  "Will Elon Musk post 190-214 tweets from April 18 to April 20, 2026?":       0.0001,
  "Will Elon Musk post 215-239 tweets from April 18 to April 20, 2026?":       0.0001,
  "Will Elon Musk post 240+ tweets from April 18 to April 20, 2026?":          0.0001,
};

return ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, decision: "hold", reason: "closed or expired" };
    }
    const mCtx = { market, timing: ctx.timing };
    const pYes = estimates[market.question] ?? 0.5;
    const probs = ctx.helpers.binaryProbsFromYesProb(mCtx, pYes);
    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];
    const label0 = market.outcomes[0]?.label;
    const label1 = market.outcomes[1]?.label;
    if (best.edge < THRESHOLD) {
      return {
        question: market.question,
        decision: "hold",
        edge: best.edge,
        pYes,
        marketYesPrice: market.outcomes.find(o => o.label === "Yes")?.price,
      };
    }
    return {
      question: market.question,
      decision: "buy",
      side: best.label,
      fairPrice: best.fairPrice,
      marketPrice: best.marketPrice,
      edge: best.edge,
      pYes,
    };
  } catch (err) {
    return { question: market.question, decision: "hold", reason: String(err) };
  }
});
